def solve(n, k):
    visited = set()
    ans = []

    def dfs(node):
        for x in range(k):
            nei = node + str(x)
            if nei not in visited:
                visited.add(nei)
                dfs(nei[1:])
                ans.append(str(x))

    start = "0" * (n - 1)
    dfs(start)

    return start + "".join(ans[::-1])

